function tr(){for(let t of document.getElementsByTagName("h1"))if(t.scrollWidth!=t.clientWidth){const e=parseFloat(window.getComputedStyle(t)["font-size"].split("px")[0]);t.style.fontSize=e*t.clientWidth/t.scrollWidth+"px"}}document.fonts.ready.then(tr),window.addEventListener("orientationchange",tr,!1);
